#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <limits.h>

#define PI 3.14159265358979323846
#define SCALE_FACTOR 300

__device__ double dev_round_double(double value) {
    int newValue = (int)(value);
    if (value - newValue < 0.5)
        return newValue;
    else
        return newValue + 1;
}

__device__ double calcLikelihoodSum(const unsigned char *I, const int *ind, int numOnes, int index) {
    double likelihoodSum = 0.0;
    for (int x = 0; x < numOnes; x++) {
        double diff1 = (double)(I[ind[index * numOnes + x]] - 100);
        double diff2 = (double)(I[ind[index * numOnes + x]] - 228);
        likelihoodSum += (diff1 * diff1 - diff2 * diff2) / 50.0;
    }
    return likelihoodSum;
}

__device__ void cdfCalc(double *CDF, const double *weights, int Nparticles) {
    CDF[0] = weights[0];
    for (int x = 1; x < Nparticles; x++) {
        CDF[x] = weights[x] + CDF[x - 1];
    }
}

__device__ double d_randu(int *seed, int index) {
    int M = INT_MAX;
    int A = 1103515245;
    int C = 12345;
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double)M));
}

__device__ double d_randn(int *seed, int index) {
    double u = d_randu(seed, index);
    double v = d_randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

__device__ double updateWeights(double *weights, const double *likelihood, int Nparticles) {
    double sum = 0;
    for (int x = 0; x < Nparticles; x++) {
        weights[x] = weights[x] * exp(likelihood[x]);
        sum += weights[x];
    }
    return sum;
}

__device__ int findIndexBin(const double *CDF, int beginIndex, int endIndex, double value) {
    if (endIndex < beginIndex)
        return -1;
    int middleIndex;
    while (endIndex > beginIndex) {
        middleIndex = beginIndex + ((endIndex - beginIndex) / 2);
        if (CDF[middleIndex] >= value) {
            if (middleIndex == 0)
                return middleIndex;
            else if (CDF[middleIndex - 1] < value)
                return middleIndex;
            else if (CDF[middleIndex - 1] == value) {
                while (middleIndex >= 0 && CDF[middleIndex] == value)
                    middleIndex--;
                middleIndex++;
                return middleIndex;
            }
        }
        if (CDF[middleIndex] > value)
            endIndex = middleIndex - 1;
        else
            beginIndex = middleIndex + 1;
    }
    return -1;
}

extern "C" __global__ void find_index_kernel(const double *arrayX, const double *arrayY,
                                  const double *CDF, double *u, double *xj,
                                  double *yj, const double *weights, int Nparticles) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < Nparticles) {
