        for (int x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) {
            index = Nparticles - 1;
        }
        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
    __syncthreads();
}

extern "C" __global__ void normalize_weights_kernel(double *weights, int Nparticles, const double *partial_sums,
                                         double *CDF, double *u, int *seed) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    __shared__ double u1;
    __shared__ double sumWeights;

    if (threadIdx.x == 0)
        sumWeights = partial_sums[0];
    __syncthreads();

    if (i < Nparticles) {
        weights[i] = weights[i] / sumWeights;
    }
    __syncthreads();

    if (i == 0) {
        cdfCalc(CDF, weights, Nparticles);
        u[0] = (1.0 / ((double)(Nparticles))) * d_randu(seed, i);
    }
    __syncthreads();

    if (threadIdx.x == 0)
        u1 = u[0];
    __syncthreads();

    if (i < Nparticles) {
        u[i] = u1 + i / ((double)(Nparticles));
    }
}

extern "C" __global__ void sum_kernel(double *partial_sums, int Nparticles) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int THREADS_PER_BLOCK = blockDim.x;

    if (i == 0) {
        double sum = 0;
        int num_blocks = (Nparticles + THREADS_PER_BLOCK - 1) / THREADS_PER_BLOCK;
        for (int x = 0; x < num_blocks; x++) {
            sum += partial_sums[x];
        }
        partial_sums[0] = sum;
    }
}

extern "C" __global__ void likelihood_kernel(double *arrayX, double *arrayY, double *xj, double *yj,
                                  double *CDF, int *ind, const int *objxy, double *likelihood,
                                  const unsigned char *I, double *u, double *weights,
                                  int Nparticles, int countOnes, int max_size, int k,
                                  int IszY, int Nfr, int *seed, double *partial_sums, double *buffer) {
    int block_id = blockIdx.x;
    int thread_id = threadIdx.x;
    int i = block_id * blockDim.x + thread_id;
    int THREADS_PER_BLOCK = blockDim.x;

    if (i < Nparticles) {
        arrayX[i] = xj[i];
        arrayY[i] = yj[i];
        weights[i] = 1.0 / ((double)(Nparticles));
        arrayX[i] = arrayX[i] + 1.0 + 5.0 * d_randn(seed, i);
        arrayY[i] = arrayY[i] - 2.0 + 2.0 * d_randn(seed, i);
    }
    __syncthreads();

    if (i < Nparticles) {
        for (int y = 0; y < countOnes; y++) {
            int indX = (int)dev_round_double(arrayX[i]) + objxy[y * 2 + 1];
            int indY = (int)dev_round_double(arrayY[i]) + objxy[y * 2];
            int idx = i * countOnes + y;
            ind[idx] = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (ind[idx] >= max_size)
                ind[idx] = 0;
        }
        likelihood[i] = calcLikelihoodSum(I, ind, countOnes, i);
        likelihood[i] = likelihood[i] / countOnes;
        weights[i] = weights[i] * exp(likelihood[i]);
    }

    buffer[thread_id] = 0.0;
    __syncthreads();

    if (i < Nparticles) {
        buffer[thread_id] = weights[i];
    }
    __syncthreads();

    for (unsigned int s = THREADS_PER_BLOCK / 2; s > 0; s >>= 1) {
        if (thread_id < s) {
            buffer[thread_id] += buffer[thread_id + s];
        }
        __syncthreads();
    }
    if (thread_id == 0) {
        partial_sums[block_id] = buffer[0];
    }
}
